const item = $input.first();
const body = item.json.body || item.json;
const b = item.binary || {};
const keys = Object.keys(b);
if (!keys.length) {
  throw new Error('No hay archivos binarios. Enviá multipart con el campo "images" (uno o más).');
}
const voice = body.voice_transcript || body.voice || '';
const batch_id = body.batch_id || $execution.id;
return keys.map((key, index) => ({
  json: {
    batch_id,
    voice_transcript: String(voice),
    filename: b[key].fileName || `ticket_${index}.jpg`,
    binaryKey: key,
  },
  binary: { image: b[key] },
}));

const FormData = require('form-data');
const orig = $('SplitOut_UnItemPorImagen').all();
const uploaded = $input.all();
if (!orig.length) throw new Error('No hay ítems originales');
if (uploaded.length !== orig.length) {
  throw new Error(`Drive devolvió ${uploaded.length} ítems, se esperaban ${orig.length}`);
}

const drive_items = uploaded.map((u, idx) => {
  const j = u.json || {};
  return {
    index: idx,
    drive_id: j.id,
    drive_web_view_link: j.webViewLink || j.webContentLink || '',
    filename: orig[idx]?.json?.filename,
  };
});

const form = new FormData();
const batch_id = orig[0].json.batch_id || $execution.id;
const voice = orig[0].json.voice_transcript || '';
if (voice) form.append('voice_transcript', voice);
form.append('batch_id', batch_id);

for (let i = 0; i < orig.length; i++) {
  const it = orig[i];
  const bin = it.binary?.image;
  let buf;
  if (bin && bin.data) {
    buf = Buffer.from(bin.data, 'base64');
  } else if (this.helpers.getBinaryDataBuffer) {
    buf = await this.helpers.getBinaryDataBuffer(i, 'image');
  } else {
    throw new Error('No se pudo leer el binario de la imagen');
  }
  const fn = it.json.filename || `ticket_${i}.jpg`;
  form.append('images', buf, { filename: fn });
}

const base = String($env.AUTODOC_CLOUD_RUN_URL || '').replace(/\/+$/, '');
if (!base) throw new Error('Variable AUTODOC_CLOUD_RUN_URL no definida');
const url = `${base}/process-batch`;
const secret = $env.X_AUTODOC_SECRET || '';
if (!secret) throw new Error('Variable X_AUTODOC_SECRET no definida');

let lastErr;
let parsed;
for (let attempt = 1; attempt <= 3; attempt++) {
  try {
    const res = await this.helpers.httpRequest({
      method: 'POST',
      url,
      headers: {
        ...form.getHeaders(),
        'X-Autodoc-Secret': secret,
      },
      body: form,
      timeout: 180000,
    });
    parsed = typeof res === 'string' ? JSON.parse(res) : res;
    lastErr = null;
    break;
  } catch (e) {
    lastErr = e;
    if (attempt < 3) await new Promise((r) => setTimeout(r, 2000 * attempt));
  }
}
if (lastErr) throw lastErr;

return [{
  json: {
    batch_http: parsed,
    drive_items,
    ticket_count: orig.length,
  },
}];

const root = $input.first().json;
const api = root.batch_http;
const driveByIndex = {};
for (const d of root.drive_items || []) driveByIndex[d.index] = d;
if (!api || !Array.isArray(api.results)) return [{ json: { Error: 'sin results', raw: root } }];
const out = [];
for (const r of api.results) {
  const link = driveByIndex[r.index]?.drive_web_view_link || '';
  const id = driveByIndex[r.index]?.drive_id || '';
  if (!r.success) {
    out.push({
      json: {
        Batch_Id: api.batch_id,
        Source_File: r.filename,
        Drive_File_Id: id,
        Drive_Link: link,
        Error: r.error || '',
        Detail: r.detail || '',
      },
    });
    continue;
  }
  for (const row of r.sheets_rows || []) {
    out.push({
      json: {
        ...row,
        Batch_Id: api.batch_id,
        Source_File: r.filename,
        Drive_File_Id: id,
        Drive_Link: link,
      },
    });
  }
}
return out.length ? out : [{ json: { Batch_Id: api.batch_id, Note: 'sin filas' } }];
